1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type Step = { op: "quote"; items: Item[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const basePremium = (item: Item): number => {
9	  if (item.type === "sword") return 100;
10	  if (item.type === "amulet") return 60;
11	  return 0;
12	};
13	
14	const quotePremium = (items: Item[]): number => {
15	  const policyBase = items.reduce((sum, item) => sum + basePremium(item), 0);
16	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
17	  return Math.ceil(policyBase + firstInsuranceSurcharge) + PROCESSING_FEE;
18	};
19	
20	export const runScenario = (input: unknown): unknown => {
21	  const scenario = input as Scenario;
22	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
23	  return { results };
24	};
25

